function parseArgs() {
  const args = process.argv.slice(2);
  const parsed = {
    input: null,
    composition: "VSL",
    output: null,
    codec: "h264",
  };

  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case "--input":
      case "-i":
        parsed.input = args[++i];
        break;
      case "--composition":
      case "-c":
        parsed.composition = args[++i];
        break;
      case "--output":
      case "-o":
        parsed.output = args[++i];
        break;
      case "--codec":
        parsed.codec = args[++i];
        break;
    }
  }

  if (!parsed.input) {
    console.error("Error: --input is required");
    console.error("Usage: node render.mjs --input data.json --composition VSL --output output.mp4");
    process.exit(1);
  }

